INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0001-0000-0000-000000000000', 'acc04b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why a Surveyor Studies Law</h3><p>A boundary survey is not merely a measurement exercise. The surveyor is asked to locate, on the ground, the limits of a <strong>legal interest in land</strong> created by deeds, grants, and statutes that may be centuries old. The measurement is the easy part; the hard part is deciding <em>which</em> evidence of a boundary the law treats as controlling. A surveyor who ignores the legal hierarchy of evidence&mdash;monuments over distances, senior rights over junior&mdash;can produce a mathematically perfect survey that is legally wrong, and a legally wrong boundary is the most expensive mistake a surveyor can make.</p><p>Property law answers <strong>who owns what</strong> and <strong>what bundle of rights</strong> ownership includes; surveying answers <strong>where</strong> that ownership lies. The two disciplines meet at the boundary line. This course gives you the legal foundation that the Surveyor-in-Training (SIT) and RPLS examinations demand, with constant attention to how <em>Texas</em> law differs from general common-law practice.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0001-0000-0000-000000000001', 'acc04b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Sources and Hierarchy of Texas Law</h3><p>Texas law is layered, and a higher source controls a lower one. In descending authority: (1) the <strong>Texas Constitution of 1876</strong> (the current constitution); (2) <strong>statutes</strong>, organized into topical codes published at statutes.capitol.texas.gov; (3) <strong>administrative rules</strong> in the <em>Texas Administrative Code</em> (TAC); and (4) <strong>case law</strong> (common law applied through stare decisis). The codes most relevant to boundary work are the <strong>Property Code</strong> (estates, conveyances, recording, deeds, easements), the <strong>Natural Resources Code</strong> (public lands and the General Land Office), and the <strong>Civil Practice &amp; Remedies Code Chapter 16</strong> (adverse possession and the limitations period for suits against surveyors).</p><p>A classic exam trap: <strong>adverse possession is in the Civil Practice &amp; Remedies Code, not the Property Code.</strong> Surveyor licensing flows from the <strong>Occupations Code Chapter 1071</strong> (the Professional Land Surveying Practices Act), with conduct standards adopted by the <strong>Texas Board of Professional Engineers and Land Surveyors (TBPELS)</strong> in <strong>22 TAC Chapter 138</strong>.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0001-0000-0000-000000000002', 'acc04b01-0000-0000-0000-000000000001', 'table', '{"headers":["Topic","Where the law lives"],"rows":[["Estates, deeds, recording, easements","Texas Property Code"],["Public lands, the GLO, patents, navigable streams","Texas Natural Resources Code"],["Adverse possession (3/5/10/25 yr)","Civil Practice & Remedies Code Ch. 16 (§§16.021–16.028)"],["Suit-against-surveyor limitations","Civ. Prac. & Rem. Code §16.011"],["Surveyor licensing (RPLS/LSLS)","Occupations Code Ch. 1071"],["Standards of practice & conduct","22 TAC Ch. 138 (TBPELS)"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0001-0000-0000-000000000003', 'acc04b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Texas Court System</h3><p>Trial courts of general jurisdiction are the <strong>District Courts</strong>; <em>title and boundary disputes&mdash;trespass-to-try-title and quiet-title actions&mdash;begin there</em> (Tex. Const. art. V, &sect;8). Below them are County Courts (constitutional and statutory \"county courts at law\"), Justice (JP) Courts, and Municipal Courts. Appeals go to the intermediate <strong>Texas Courts of Appeals</strong>. Texas then has <strong>two co-equal highest courts</strong>: the <strong>Supreme Court of Texas</strong>, the final authority for civil cases (so boundary and title cases end there), and the <strong>Texas Court of Criminal Appeals</strong>, final only for criminal cases. Texas shares this split-apex design with only one other state, Oklahoma.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0001-0000-0000-000000000004', 'acc04b01-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Most states and the federal system have a single court of last resort hearing both civil and criminal appeals. Texas splits this in two. Because boundary/title disputes are civil, the apex authority for surveying precedent is the Supreme Court of Texas; the Court of Criminal Appeals never touches boundary law."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0001-0000-0000-000000000005', 'acc04b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Surveyor''s Lane vs. the Attorney''s Lane</h3><p>A surveyor <strong>locates boundaries</strong>; a surveyor does <strong>not</strong> adjudicate ownership or render legal opinions on title. When you retrace a boundary you reconstruct where the original line was run and marked, applying legal rules of evidence (dignity of calls, footsteps of the original surveyor) to physical and record evidence. Deciding <em>who owns</em> a disputed strip, quieting title, or interpreting an ambiguous reservation is the work of a court and counsel. The professional skill is staying in your lane: report what the evidence shows the boundary to be, flag conflicts and gaps/overlaps, and route the legal questions to the parties'' attorneys. Rendering a title opinion or otherwise practicing law without a license exposes the surveyor to liability and to TBPELS discipline.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0001-0000-0000-000000000006', 'acc04b01-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Property law defines ownership; surveying locates it on the ground; they meet at the boundary line.","The Texas legal hierarchy is Constitution → statutes (codes) → administrative rules (TAC) → case law.","Boundary/title suits begin in District Court and end at the Supreme Court of Texas (a civil matter).","Adverse possession lives in Civ. Prac. & Rem. Code Ch. 16, not the Property Code — a common exam trap.","Surveyors locate boundaries and flag conflicts; they do not render title opinions or practice law."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0002-0000-0000-000000000000', 'acc04b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Bundle of Rights</h3><p>Ownership of land is best understood as a <strong>bundle of rights</strong> rather than a single thing: the right to <em>possess</em>, to <em>use</em>, to <em>exclude</em> others, to <em>transfer</em> (sell, lease, gift, devise), and to <em>profit</em>. These sticks can be separated. An owner may sell the surface but reserve the minerals, grant an easement (a right of use) without surrendering possession, or lease the land while keeping the fee. In Texas the <strong>mineral estate</strong> is frequently severed and is the <em>dominant</em> estate&mdash;the mineral owner may use as much of the surface as is reasonably necessary to develop the minerals. A surveyor must know which sticks a particular survey is being asked to locate.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0002-0000-0000-000000000001', 'acc04b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Freehold Estates</h3><p>The largest estate is <strong>fee simple absolute</strong>&mdash;ownership of potentially infinite duration with no inherent condition. <strong>Defeasible fees</strong> are fee estates that may end on the happening of an event: a <strong>fee simple determinable</strong> uses durational words (\"so long as,\" \"until\") and automatically reverts, leaving the grantor a <strong>possibility of reverter</strong>; a <strong>fee simple subject to condition subsequent</strong> uses conditional words (\"but if,\" \"provided that\") and leaves the grantor a <strong>right of re-entry / power of termination</strong> that must be exercised. A <strong>life estate</strong> lasts for the measuring life (it may be <em>pur autre vie</em>, measured by another''s life); the life tenant owes a duty not to commit <strong>waste</strong>. Future interests include the <strong>remainder</strong> (in a third party) and the <strong>reversion</strong> (retained by the grantor).</p><p>Texas <strong>presumes that a conveyance passes the entire estate (fee simple)</strong> unless a lesser estate is expressly limited&mdash;Tex. Prop. Code &sect;5.001 (\"unless the estate is limited by express words or unless a lesser estate is conveyed\").</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0002-0000-0000-000000000002', 'acc04b02-0000-0000-0000-000000000001', 'table', '{"headers":["Estate","Typical language","Future interest left"],"rows":[["Fee simple absolute","\"to A and her heirs\"","None"],["Fee simple determinable","\"so long as / until\"","Possibility of reverter (grantor)"],["Fee simple subject to condition subsequent","\"but if / provided that\"","Right of re-entry / power of termination"],["Life estate","\"to A for life\"","Reversion (grantor) or Remainder (third party)"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0002-0000-0000-000000000003', 'acc04b02-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Tex. Prop. Code §5.042 abolishes the Rule in Shelley''s Case, the rule forbidding a remainder to the grantor''s heirs, the Doctrine of Worthier Title, and a homestead-lien rule — giving such limitations effect according to grantor intent. Note: §5.042 does NOT abolish the destructibility of contingent remainders; Texas rejects that doctrine by case law, not by §5.042."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0002-0000-0000-000000000004', 'acc04b02-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Why estates matter to a surveyor","content":"<p>A surveyor locates the <strong>physical extent</strong> of an estate, not its quality, but the kind of estate shapes the survey. A severed mineral estate may require depicting unit boundaries; a life estate plus remainder means two owners must be considered for access and signatures; a defeasible fee''s condition can revest title and change who the abutting owner is. When the deed limits a lesser estate or reserves rights, the surveyor must read those words carefully because they define what bundle of sticks the boundary encloses.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0002-0000-0000-000000000005', 'acc04b02-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Ownership is a bundle of separable rights (possess, use, exclude, transfer, profit).","Fee simple absolute is the largest estate; defeasible fees end on an event and leave a future interest.","Texas presumes a conveyance passes the whole fee unless a lesser estate is expressly limited (§5.001).","Texas abolished Shelley''s Case and Worthier Title by §5.042 — but NOT destructibility of contingent remainders.","In Texas the severed mineral estate is the dominant estate over the surface."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0003-0000-0000-000000000000', 'acc04b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Three Workhorse Deeds</h3><p>Three deed types dominate Texas conveyancing. A <strong>general warranty deed</strong> warrants title against <em>all</em> defects, reaching back through the entire chain of title; the grantor must defend against any lawful claim \"whomsoever.\" A <strong>special warranty deed</strong> warrants only against defects arising \"by, through, or under\" the grantor&mdash;not against earlier links in the chain. A <strong>quitclaim deed</strong> conveys only <em>whatever interest, if any, the grantor happens to have</em>, with no warranty; it is <strong>not a muniment of title</strong> and does not even assert that the grantor owns anything.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0003-0000-0000-000000000001', 'acc04b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Texas Statutory Form and Implied Covenants</h3><p>Tex. Prop. Code &sect;5.022 supplies the statutory warranty-deed form using the operative words \"grant, sold, and conveyed\" and \"<strong>warrant and forever defend</strong> &hellip; against every person whomsoever lawfully claiming.\" A warranty, however, is not required (&sect;5.022(b)). Tex. Prop. Code &sect;5.023 says the words \"grant\" or \"convey\" imply <em>only</em> two covenants: (1) the grantor has not previously conveyed the same estate to another, and (2) the estate is free from encumbrances. Notably, &sect;5.023 does <strong>not</strong> imply that the grantor actually owns the property&mdash;the broad protection of a general warranty comes from the express \"warrant and forever defend\" language, not from the implied covenants.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0003-0000-0000-000000000002', 'acc04b03-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: At common law the word ''grant'' implied a covenant of seisin (that the grantor actually owns the estate). Texas §5.023 deliberately narrows the implied covenants to no-prior-conveyance + no-encumbrances. Broad title protection comes only from the express warranty language of §5.022."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0003-0000-0000-000000000003', 'acc04b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Construing a Deed: Intent Within the Four Corners</h3><p>The controlling objective in construing a deed is the <strong>intent of the parties as expressed within the four corners</strong> of the instrument, read in light of the surrounding circumstances, harmonizing all parts so that none is rendered meaningless. Modern Texas deed-construction cases (e.g., <em>Bass v. Harper</em>, 441 S.W.2d 825 (Tex. 1969)) emphasize this four-corners, harmonize-the-whole method. When provisions truly cannot be harmonized, a <strong>specific (metes-and-bounds) description controls over a general one</strong> (see <em>Concho Resources, Inc. v. Ellison</em> (Tex. 2021)). The dignity-of-calls hierarchy you study in Week 7 is a <em>subordinate</em> tool used to <em>find</em> intent when the descriptive language conflicts.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0003-0000-0000-000000000004', 'acc04b03-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"The Texas quitclaim peculiarity (and the 2021 statutory softening)","content":"<p>Classically, a grantee under a <strong>quitclaim</strong> (and successors) is <em>generally NOT a bona fide purchaser</em>: the quitclaim is treated as notice that the grantor''s title may be defective, so the grantee takes subject to prior outstanding claims even though value was paid without actual notice (<em>Woodward v. Ortiz</em>, 237 S.W.2d 286 (Tex. 1951); <em>Houston Oil Co. of Texas v. Niles</em>, 255 S.W. 604 (Tex. Comm''n App. 1923)). Whether an instrument is really a quitclaim turns on the granting language taken as a whole, not the label&mdash;a deed that conveys the <em>property itself</em> may support BFP status while one conveying only the grantor''s \"right, title, and interest\" does not (<em>Cook v. Smith</em>, 174 S.W. 1094 (Tex. 1915); <em>Geodyne Energy Income Prod. P''ship I-E v. Newton Corp.</em>, 161 S.W.3d 482 (Tex. 2005)). A quitclaim \"is not a conveyance or a muniment of title\" (<em>Rogers v. Ricane Enters.</em>, 884 S.W.2d 763 (Tex. 1994)).</p><p><strong>2026 update:</strong> Tex. Prop. Code <strong>&sect;13.006</strong> (eff. Sept. 1, 2021) provides that after the <strong>fourth anniversary</strong> of recording, a quitclaim no longer affects the good faith of, or gives notice to, a subsequent purchaser or creditor. So for quitclaims recorded on/after Sept. 1, 2021, there is now a four-year cleansing window. The classic rule still applies to the immediate grantee and during the first four years&mdash;teach the two together.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0003-0000-0000-000000000005', 'acc04b03-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["General warranty = defends all defects; special warranty = only grantor''s own acts; quitclaim = grantor''s interest ''if any.''","Texas implied covenants (§5.023) are only no-prior-conveyance and no-encumbrances — not seisin.","Deeds are construed by intent within the four corners, harmonizing every part.","A specific (metes-and-bounds) description controls over a general one when they cannot be reconciled.","A Texas quitclaim grantee is generally not a BFP; §13.006 (2021) adds a four-year cleansing window downstream."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0004-0000-0000-000000000000', 'acc04b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What a Metes-and-Bounds Description Must Do</h3><p>A metes-and-bounds description must unambiguously identify a single <strong>closed</strong> parcel. It starts at a defined <strong>Point of Beginning (POB)</strong>, runs a continuous series of measured calls&mdash;each a <em>bearing and distance</em> (e.g., \"N 12&deg;30'' E, 210.50 ft\")&mdash;around the perimeter, ties those calls to monuments, and returns to the POB so the figure mathematically <strong>closes</strong>. A description that does not close is legally defective. The governing standard is <strong>22 TAC &sect;138.91</strong>, which requires \"a definite and unambiguous identification of the location of such boundaries\" and that the description \"describe all monuments found or placed.\"</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0004-0000-0000-000000000001', 'acc04b04-0000-0000-0000-000000000001', 'table', '{"headers":["Element","What it provides"],"rows":[["Caption / heading","County, original GLO survey + abstract number, parent-tract record reference, acreage"],["Point of Beginning (POB)","Origin of the perimeter, tied to a corner of the original survey"],["Bearings & distances (calls)","Direction + length for each course, with a stated basis of bearing"],["Monuments","Natural (creeks, trees) and artificial (iron rods, fences); state which found vs. placed"],["Area / quantity","Acreage — the least reliable element; a check, not a control"],["Closure","Calls must return to the POB forming a closed figure"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0004-0000-0000-000000000002', 'acc04b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Texas Anchor: Original Survey and Abstract Number</h3><p>Because Texas land was never federal public domain, every description is located within&mdash;and tied to&mdash;the <strong>original land-grant survey</strong>. A Texas caption almost always recites the grantee and abstract number, e.g., \"situated in the <strong>H. &amp; T.C.R.R. Co. Survey, Abstract No. ___</strong>, [County] County, Texas.\" The POB and at least one controlling corner tie back to a corner of that original survey so the parcel can be relocated independently of the surveyor''s own work. Bearings reference a stated <strong>basis of bearing</strong> (22 TAC &sect;138.91(c))&mdash;today typically the Texas State Plane Coordinate System on NAD83; historic descriptions used magnetic or assumed bearings, a known source of rotation discrepancies in retracement.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0004-0000-0000-000000000003', 'acc04b04-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: PLSS states anchor a description to a section/township/range corner. Texas anchors to an original land-grant survey + abstract number, administered by the General Land Office (a state, not federal, body). You cannot read a Texas description in township/range terms."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0004-0000-0000-000000000004', 'acc04b04-0000-0000-0000-000000000001', 'callout', '{"type":"error","text":"Do not cite 22 TAC Chapter 663. After HB 1523 (2019) merged the boards into TBPELS, the surveying Professional and Technical Standards were recodified into 22 TAC Chapter 138, Subchapter E (§§138.81 et seq.). Citing §663 is outdated for 2026."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0004-0000-0000-000000000005', 'acc04b04-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A closed metes-and-bounds tract tied to a corner of the original GLO survey/abstract, with bearing-distance calls and found/set monuments."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0004-0000-0000-000000000006', 'acc04b04-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A metes-and-bounds description runs continuous bearing-distance calls around a closed perimeter back to the POB.","Texas captions tie to the original GLO survey + abstract number, not a PLSS grid.","Monuments control over bearings/distances; stated area is the least reliable element.","State the basis of bearing (22 TAC §138.91(c)); historic magnetic bearings cause rotation discrepancies.","Current standards are 22 TAC Ch. 138, Subch. E — never cite the repealed Ch. 663."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0005-0000-0000-000000000000', 'acc04b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Three Ways to Describe Land</h3><p>American descriptions take three principal forms: <strong>metes and bounds</strong> (a perimeter of bearing-distance calls, Week 4), the <strong>Public Land Survey System (PLSS)</strong> rectangular grid, and <strong>lot-and-block</strong> reference to a recorded plat. A competent surveyor reads all three, but in Texas you will draft metes-and-bounds and lot-and-block and will only <em>encounter</em> the PLSS when working across a state line or in conveyances copied from PLSS jurisdictions.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0005-0000-0000-000000000001', 'acc04b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The PLSS Rectangular System</h3><p>In the federal public-land states, land disposal was organized by the federal General Land Office (now the BLM) into a rectangular grid. From an <strong>initial point</strong> (a principal meridian crossing a base line), land is divided into <strong>townships</strong> roughly six miles square, located by <strong>township</strong> (north/south rows) and <strong>range</strong> (east/west columns). Each township is divided into 36 <strong>sections</strong> of about one square mile (640 acres), numbered 1&ndash;36 in a boustrophedonic (back-and-forth) pattern, then into aliquot parts (NE&frac14;, S&frac12;, etc.). Lost PLSS corners are restored under the BLM <em>Manual of Surveying Instructions</em> using single- and double-proportionate measurement.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0005-0000-0000-000000000002', 'acc04b05-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Texas entered the Union retaining its public lands, so its land was never surveyed under the federal PLSS. There is no township-range-section grid in Texas. Texas uses irregular metes-and-bounds tracts identified by original survey name + abstract number, administered by the GLO. The two systems are mathematically unrelated."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0005-0000-0000-000000000003', 'acc04b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Lot-and-Block (Recorded-Plat) Descriptions</h3><p>When a developer subdivides land, the surveyor prepares a <strong>plat</strong> showing numbered lots within blocks, streets, easements, and dimensions, and records it with the county clerk. Thereafter a parcel can be described simply by <strong>lot, block, subdivision name, and the plat''s recording data</strong> (e.g., \"Lot 7, Block C, Oak Hollow Subdivision, according to the plat recorded in Vol. __, Page __, Plat Records, Travis County, Texas\"). The recorded plat is the controlling document; the lots are created <strong>simultaneously</strong>, which (as you will see in Week 7) means excess or deficiency is <em>apportioned</em> among them rather than resolved by seniority.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0005-0000-0000-000000000004', 'acc04b05-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Even a metes-and-bounds split can trigger Texas subdivision control. Loc. Gov''t Code §212.004 (''Plat Required'') states that a division of a tract into a subdivision includes a division ''made by using a metes and bounds description in a deed of conveyance,'' so you cannot evade platting merely by avoiding a formal plat."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0005-0000-0000-000000000005', 'acc04b05-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["PLSS = federal rectangular grid: initial point, township/range, 36 sections per township (~640 ac each).","Texas never adopted the PLSS; it uses original survey + abstract metes-and-bounds.","Lot-and-block describes a parcel by lot, block, subdivision name, and plat recording data.","Recorded-plat lots are created simultaneously, so excess/deficiency is apportioned, not resolved by seniority.","A metes-and-bounds split into a subdivision can still require a recorded plat (Loc. Gov''t Code §212.004)."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0006-0000-0000-000000000000', 'acc04b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Four Sovereigns of the Soil</h3><p>Every parcel of privately held Texas land traces backward through a chain of deeds to an original grant from a <strong>sovereign</strong>. There are four, in order: <strong>Spain</strong> (1716&ndash;1821), <strong>Mexico</strong> (1821&ndash;1836), the <strong>Republic of Texas</strong> (1836&ndash;1845), and the <strong>State of Texas</strong> (1845&ndash;present). A Spanish or Mexican grant is a <em>title</em>; a Republic or State grant is a <em>patent</em>. Either instrument <strong>severs the land from the sovereign</strong>, and every later deed runs from that first grantee. Perfected Spanish and Mexican titles remain valid today and the land they conveyed <em>cannot be re-patented</em>&mdash;sovereignty was already severed. The Republic distributed huge acreage through <strong>headright certificates</strong>; a first-class headright gave a resident head of family one league and one labor (about 4,605 acres).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0006-0000-0000-000000000001', 'acc04b06-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Annexation (1845) and the General Land Office","content":"<p>Texas was an <strong>independent republic from 1836 to 1845</strong>. By the Joint Resolution for Annexing Texas (Mar. 1, 1845), Texas \"retain[ed] all the vacant and unappropriated lands lying within its limits\"&mdash;the federal government did <em>not</em> take the public domain. Texas kept well over 200 million acres and dedicated land revenue to the Permanent School Fund. The <strong>General Land Office (GLO)</strong>, founded December 22, 1836, is the oldest existing Texas state agency; it maintains the grant archive (roughly 35.5 million land-grant records back to 1720, including the Spanish Collection of ~4,200 Spanish/Mexican grants) and <strong>still issues patents</strong>. This single fact&mdash;state, not federal, source of title&mdash;explains most of what makes Texas boundary law distinctive.</p>","open":false}]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0006-0000-0000-000000000002', 'acc04b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Texas Surveying Units: Vara, Labor, League</h3><p>Original Texas field notes are frequently written in <strong>varas</strong>. Texas law fixes the vara at <strong>exactly 33&frac13; inches</strong> = 2.7778 ft (36 varas = exactly 100 ft). Area units scale up from it: a <strong>labor</strong> is 1,000,000 square varas (about 177.1 acres, the farming unit) and a <strong>league</strong> (legua/sitio) is 25,000,000 square varas (about 4,428.4 acres, the grazing unit, = 25 labors). A standard married head-of-family colonization grant was one league plus one labor (about 4,605.5 acres). A retracing surveyor must convert varas to feet (multiply by 2.7778, or divide by 0.36) and reconcile the historic magnetic/assumed bearing basis to a modern datum.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0006-0000-0000-000000000003', 'acc04b06-0000-0000-0000-000000000001', 'table', '{"headers":["Unit","Definition","Approx. acres"],"rows":[["Vara","33⅓ in = 2.7778 ft","—"],["Labor","1,000,000 sq varas (1,000 varas square)","~177.1"],["League (sitio)","25,000,000 sq varas (5,000 varas square) = 25 labors","~4,428.4"],["League + labor","26,000,000 sq varas (standard family grant)","~4,605.5"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0006-0000-0000-000000000004', 'acc04b06-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Texas kept the Spanish/Mexican grant system and never adopted the PLSS. Use the Texas vara of 33⅓ in; do not apply a foreign vara value (Spanish ''vara de Burgos'' ~32.9 in, Mexican vara ~32.99 in) to a Texas grant, or computed acreages will drift."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0006-0000-0000-000000000005', 'acc04b06-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Four sovereigns: Spain, Mexico, the Republic, the State; a ''title'' (Spain/Mexico) or ''patent'' (Republic/State) severs sovereignty.","Texas retained its public lands at annexation (1845); the land was never federal public domain.","The GLO (est. 1836) holds the grant archive and still issues patents.","Texas vara = exactly 33⅓ in (2.7778 ft); 36 varas = 100 ft.","Labor ≈ 177 ac; league ≈ 4,428 ac (= 25 labors); standard family grant ≈ 4,605 ac."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0007-0000-0000-000000000000', 'acc04b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Dignity of Calls</h3><p>When the calls within a single description conflict, the law ranks them by relative reliability&mdash;their <strong>\"dignity\"</strong>&mdash;highest to lowest: (1) <strong>natural monuments</strong> (rivers, creeks, lakes, rocks); (2) <strong>artificial monuments</strong> (marked trees, stakes, set iron, fences); (3) <strong>adjoinder</strong> (an adjacent, already-established survey line&mdash;a modern Texas refinement inserted here); (4) <strong>course</strong> (bearing); (5) <strong>distance</strong>; and (6) <strong>quantity / area</strong> (the weakest). The idea is that the more permanent and identifiable a call, the more it reflects what was actually on the ground when the line was run, and the harder it is to fabricate.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0007-0000-0000-000000000001', 'acc04b07-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Case: Stafford v. King, 30 Tex. 257 (1867)","content":"<p><em>Stafford v. King</em> is the foundational Texas authority on both the dignity of calls and the footsteps doctrine. The Court explained: \"Natural objects are mountains, lakes, rivers, creeks, rocks, and the like. Artificial objects are marked lines, trees, stakes, etc.\" and that \"course and distance are the most unreliable calls&hellip;hence the general rule, that course and distance yield to natural objects.\" It summarized the controlling order as \"1, natural objects; 2, artificial objects; 3, course and distance.\" Crucially, <em>Stafford</em> also anchors the <strong>footsteps rule</strong>: \"The actual identification of the survey, the footsteps of the surveyor upon the ground, should always be followed, by whatever rule they may be traced.\" The hierarchy is only a <em>rule of construction</em>; it always yields to the intent apparent on the face of the grant and to the original surveyor''s footsteps where they can be retraced.</p>","open":false}]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0007-0000-0000-000000000002', 'acc04b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Intent and Footsteps Are Paramount</h3><p>The dignity hierarchy is a <em>subordinate</em> tool used to <strong>find the parties'' intent</strong> when the descriptive language conflicts. The cardinal Texas principle is that a retracing surveyor and the court must <strong>follow the footsteps of the original surveyor</strong> and give effect to the grant''s intent, locating lines where they were actually run even against later \"more accurate\" measurements (<em>Silver Oil &amp; Gas, Inc. v. EOG Resources, Inc.</em>, 246 S.W.3d 197 (Tex. App.&mdash;San Antonio 2007)). A found, identifiable original monument controls over a conflicting field-note call. The exact location of a boundary line is ultimately a <strong>question of fact</strong>.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0007-0000-0000-000000000003', 'acc04b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Sequential vs. Simultaneous Conveyances</h3><p>How a discrepancy is resolved depends on how the parcels were created. <strong>Sequential</strong> conveyances&mdash;tracts carved out one after another over time&mdash;are governed by <strong>senior/junior rights</strong>: the earlier (senior) deed takes the full measure of what its description grants, and the later (junior) deed takes only the remainder; a grantor cannot convey land already conveyed to the senior grantee, so the junior absorbs any excess or eats any deficiency. <strong>Simultaneous</strong> conveyances&mdash;multiple lots created at one instant from a recorded subdivision plat&mdash;have <em>no</em> senior lot; excess or deficiency found between controlling monuments is <strong>apportioned proportionately</strong> among the lots according to their record lengths (single proportionate measurement). Apportionment is a last resort: <em>found monuments and original corners control first</em>.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0007-0000-0000-000000000004', 'acc04b07-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs / caution: The single/double ''proportionate measurement'' methods are PLSS/BLM-Manual constructs. No marquee Texas Supreme Court case adopts them by name; in Texas, apportionment is established common-law surveying practice and a genuine last resort behind found monuments and the original surveyor''s footsteps."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0007-0000-0000-000000000005', 'acc04b07-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Sequential conveyance (senior takes full description; junior takes the residue) vs. simultaneous plat (excess/deficiency apportioned across lots)."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0007-0000-0000-000000000006', 'acc04b07-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Dignity of calls: natural > artificial > adjoinder > course > distance > quantity.","Stafford v. King (1867) is the Texas root of both the dignity hierarchy and the footsteps doctrine.","Intent and the original surveyor''s footsteps are paramount; the hierarchy only helps find them.","Sequential conveyances → senior/junior rights; simultaneous (plat) conveyances → proportionate apportionment.","Found monuments control first; proportioning is a last resort, not a Texas marquee holding."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0008-0000-0000-000000000000', 'acc04b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Midterm Scope and Strategy</h3><p>The Week 8 midterm is a comprehensive checkpoint over the first half of the course (Weeks 1&ndash;7). Expect scenario questions that ask you to <em>apply</em> doctrine rather than recite it: trace a chain of title to its sovereign source, classify a deed and its warranties, identify the controlling call in a conflicting description, and explain how Texas law diverges from general common law. Treat each fact pattern the way a court does&mdash;find the <strong>intent</strong> first, then use the dignity-of-calls hierarchy only as a tie-breaker.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0008-0000-0000-000000000001', 'acc04b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>High-Yield Review</h3><p>Concentrate your review on the points that are both heavily tested and Texas-specific. From Weeks 1&ndash;3: the hierarchy of Texas law, the split-apex court system, the &sect;5.042 abolitions (Shelley''s Case, Worthier Title&mdash;<em>not</em> destructibility), the narrowed implied covenants of &sect;5.023, and the quitclaim/BFP rule with its 2021 &sect;13.006 four-year cleansing window. From Weeks 4&ndash;7: the required elements of a metes-and-bounds description, the abstract-number anchor, why Texas has no PLSS grid, the vara/labor/league conversions, and the dignity of calls anchored in <em>Stafford v. King</em> with the footsteps doctrine.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0008-0000-0000-000000000002', 'acc04b08-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Exam tip: Whenever a question presents conflicting calls, resolve it in this order — (1) parties'' intent within the four corners, (2) footsteps of the original surveyor / found monuments, then (3) the dignity hierarchy. The mechanical hierarchy is the last step, not the first."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0008-0000-0000-000000000003', 'acc04b08-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The midterm is application-focused over Weeks 1–7; reason like a court, not a flashcard.","Master the Texas-specific traps: §5.042, §5.023, §13.006, Ch. 138 vs. repealed Ch. 663.","Resolve call conflicts by intent → footsteps/monuments → dignity hierarchy.","Be fluent in vara/labor/league conversions and the four sovereigns of the soil."]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0009-0000-0000-000000000000', 'acc04b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Two Fundamentally Different Jobs</h3><p>An <strong>original survey</strong> <em>creates</em> boundaries that did not previously exist&mdash;subdividing a tract, laying out a new street, establishing the lines of a fresh grant. A <strong>retracement (resurvey)</strong> does something very different: it <strong>re-establishes the lines and corners of an existing survey</strong>. A retracement never creates or relocates a boundary; it recovers where the original line already is. Confusing the two is a classic error: a surveyor who \"corrects\" an original line to make the measurements close better has improperly moved a boundary and exposed everyone to litigation.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0009-0000-0000-000000000001', 'acc04b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Footsteps Doctrine Governs Retracement</h3><p>In Texas retracement the controlling rule is the <strong>footsteps of the original surveyor</strong>: where the original surveyor''s actual lines and corners on the ground can be ascertained, they <strong>control even over inconsistent field-note calls</strong>. The dignity-of-calls hierarchy (Week 7) is a fallback, invoked only when those footsteps cannot be retraced. As the San Antonio court put it in <em>Silver Oil &amp; Gas, Inc. v. EOG Resources, Inc.</em>, \"the cardinal rule is that the footsteps of the original surveyor, if they can be ascertained, should be followed\"; absent ascertainable footsteps you prioritize natural &rarr; artificial &rarr; course &rarr; distance. The <em>location</em> of a survey line is a <strong>question of fact</strong> (<em>TH Investments, Inc. v. Kirby Inland Marine, L.P.</em>, 218 S.W.3d 173 (Tex. App.&mdash;Houston [14th Dist.] 2007)).</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0009-0000-0000-000000000002', 'acc04b09-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"The GLO and the LSLS credential","content":"<p>Because Texas titles flow from <strong>original GLO surveys and patents</strong> rather than a uniform federal grid, retracing the original surveyor''s actual work is the dominant Texas methodology. A surveyor retracing an original grant must consult the <strong>General Land Office</strong> record&mdash;patents, field notes, sketches, maps&mdash;to locate original grant boundaries and corners, then follow the footsteps on the ground. Original surveys of <em>state</em> land, and corrections to original grant boundaries, require a <strong>Licensed State Land Surveyor (LSLS)</strong>, a higher GLO-issued credential than the RPLS. The Occupations Code (&sect;1071.002) defines \"state land surveying\" to include \"determining by survey the location or relocation of original land grant boundaries and corners\" and filing field notes in the GLO.</p>","open":false}]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0009-0000-0000-000000000003', 'acc04b09-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: PLSS states restore lost corners under the BLM Manual''s proportionate-measurement rules on a federal grid. Texas retained and surveyed its own public domain, so Texas retracement centers on the original Texas surveyor''s monuments and footsteps administered through GLO records, with proportioning used only as a last resort."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0009-0000-0000-000000000004', 'acc04b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Lost vs. Obliterated Corners</h3><p>A key retracement distinction: an <strong>obliterated</strong> corner is one whose physical evidence is gone but whose position can still be recovered from <em>collateral evidence</em>&mdash;occupation lines, fences, witness testimony, ties to adjacent monuments. A <strong>lost</strong> corner is one that cannot be recovered by any acceptable evidence and must be re-established by measurement (proportioning, on a plat). The surveyor''s duty is to <strong>exhaust the search for evidence of the original position before declaring a corner lost</strong>. Too many boundary disputes arise because a surveyor proportioned a corner that was merely obliterated and recoverable.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0009-0000-0000-000000000005', 'acc04b09-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["An original survey creates boundaries; a retracement re-establishes existing ones — it never moves them.","The footsteps of the original surveyor control retracement, even over inconsistent field-note calls.","The dignity hierarchy is a fallback used only when footsteps cannot be retraced.","Distinguish obliterated corners (recoverable from collateral evidence) from lost corners (re-established by measurement).","The GLO holds original-grant records; original state-land boundary work requires an LSLS."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0010-0000-0000-000000000000', 'acc04b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Riparian vs. Littoral; Navigable vs. Non-Navigable</h3><p><strong>Riparian</strong> rights attach to land bordering a <em>flowing watercourse</em> (a river or stream); <strong>littoral</strong> rights attach to land bordering a <em>static body</em> (a lake, the sea, the Gulf). For a <strong>non-navigable</strong> stream the abutting owner''s title runs to the <em>center thread</em> of the channel. For a <strong>navigable</strong> stream private title stops at the bank (the gradient boundary) and the <strong>State owns the bed</strong>, holding it in trust for the public. The classification therefore decides who owns the land under the water&mdash;a question the surveyor must answer before locating the line.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0010-0000-0000-000000000001', 'acc04b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The 30-Foot Rule and State Ownership of Beds</h3><p>Texas supplies a bright-line geometric test of navigability: a stream is <strong>navigable in fact</strong> (and thus public, with a State-owned bed) if it \"<strong>retains an average width of 30 feet from its mouth up</strong>\" (Tex. Nat. Res. Code <strong>&sect;21.001(3)</strong>, originating in an 1837 Republic act). The 30 feet is measured across the <em>entire bed</em> between banks, not the water flowing on any given day&mdash;so a channel that is sometimes dry can still be navigable. The <strong>State of Texas owns the beds of navigable streams</strong>, subject to the 1929 \"Small Bill,\" which relinquished the bed <em>surface</em> to certain abutting owners while <strong>reserving the minerals to the State</strong> and preserving the public''s rights in the water.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0010-0000-0000-000000000002', 'acc04b10-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Case: Motl v. Boyd — the gradient boundary","content":"<p>The landward limit of the bed of a navigable Texas stream is the <strong>gradient boundary</strong>: a graded line along the bank <em>midway between</em> (i) the lower water level that just reaches the cut bank and (ii) the higher level that just does not overtop it&mdash;tied to the \"cut bank\" or \"qualified bank.\" The Texas Supreme Court adopted this in <em>Motl v. Boyd</em>, 116 Tex. 82, 286 S.W. 458 (1926), defining the \"bed\" as the soil \"alternately covered and left bare&hellip;at its average and mean stage during an entire year,\" excluding extreme freshets and droughts. The method was developed by surveyor Arthur A. Stiles for the Red River line in <em>Oklahoma v. Texas</em>, 260 U.S. 606 (1923), and refined in <em>Brainard v. State</em>, 12 S.W.3d 6 (Tex. 2000) as the mid-height point of the lowest qualified bank in the vicinity. It is a difficult expert survey&mdash;do not equate it with a simple high-water line.</p>","open":false}]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0010-0000-0000-000000000003', 'acc04b10-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Most states fix the riparian boundary at the ordinary high-water mark (an observable vegetation/scour line). Texas instead uses a computed gradient line at the mid-height of the qualified bank, requiring water-level observation and bank profiling. The 30-ft average-width navigability test is also essentially unique to Texas."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0010-0000-0000-000000000004', 'acc04b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Coastal Boundaries: The Dual Datum and Avulsion</h3><p>On the coast the seaward boundary of upland depends on the <strong>sovereign source of the grant</strong> (<em>Luttes v. State</em>, 159 Tex. 500, 324 S.W.2d 167 (1959)): a <strong>Spanish/Mexican</strong> grant is bounded by <strong>mean higher high water (MHHW)</strong>&mdash;the average of the higher of the two daily high tides over an ~18.6-year epoch, which pushes the line landward&mdash;while an <strong>Anglo-American (Republic/State)</strong> grant is bounded by <strong>mean high tide / mean high water</strong>. A coastal surveyor must first trace the chain of title to the original sovereign before choosing a datum. Finally, boundaries shift with <strong>gradual</strong> change (accretion adds land, erosion removes it) but are <strong>fixed</strong> by <strong>avulsion</strong>&mdash;a sudden, perceptible change such as a flood cutting a new channel does not move the boundary (and, under <em>Severance v. Patterson</em>, 370 S.W.3d 705 (Tex. 2012), does not automatically \"roll\" a public beach easement onto formerly private land).</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0010-0000-0000-000000000005', 'acc04b10-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Riparian = flowing watercourse; littoral = static body. Non-navigable: title to the center thread; navigable: State owns the bed.","A Texas stream is navigable if its bed averages 30 ft wide (§21.001(3)); the State owns navigable beds.","The boundary of a navigable Texas stream is the gradient boundary (Motl v. Boyd; Brainard), not the OHWM.","Coastal datum follows the sovereign: Spanish/Mexican = MHHW; Anglo/Texas = mean high tide (Luttes v. State).","Gradual change moves the boundary; avulsion fixes it (Severance v. Patterson)."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0011-0000-0000-000000000000', 'acc04b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>A Wholly Statutory, Multi-Track Scheme</h3><p>Adverse possession in Texas is <strong>entirely statutory</strong> and lives in the <strong>Civil Practice &amp; Remedies Code, Chapter 16</strong> (not the Property Code). Section 16.021 defines the key terms: <strong>adverse possession</strong> is \"an actual and visible appropriation of real property, commenced and continued under a claim of right that is inconsistent with and is hostile to the claim of another person\"; <strong>peaceable possession</strong> is continuous possession not interrupted by an adverse suit. Rather than one common-law test, Texas offers <strong>five distinct limitation periods</strong>, each with its own elements; a claimant pleads under the track whose requirements it can satisfy.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0011-0000-0000-000000000001', 'acc04b11-0000-0000-0000-000000000001', 'table', '{"headers":["Statute","Period","Core requirement"],"rows":[["§16.024","3 yr","Peaceable & adverse possession under title or color of title (strongest paper basis → shortest period)"],["§16.025","5 yr","Cultivate/use/enjoy + pay applicable taxes + claim under a duly registered deed (excludes quitclaim/forged)"],["§16.026","10 yr","Peaceable & adverse, cultivating/using/enjoying; no instrument/tax needed but capped at 160 acres unless enclosed or under a recorded deed fixing boundaries"],["§16.027","25 yr","Runs regardless of any legal disability (minority, unsound mind) — absolute long-stop"],["§16.028","25 yr","Under a recorded instrument purporting to convey, even if void on its face (excludes quitclaim/forged); extends to the whole area described"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0011-0000-0000-000000000002', 'acc04b11-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: The §16.025 five-year track requires PAYING PROPERTY TAXES each year — a single missed year is fatal. This tax requirement is absent from traditional common law and is a frequent claim-killer. The §16.026 160-acre cap (absent enclosure or a recorded deed) also has no general common-law analog."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0011-0000-0000-000000000003', 'acc04b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Tacking, Encroachments, and Acquiescence</h3><p><strong>Tacking</strong> across successive possessors is allowed where they are in <em>privity</em>, but the statutory prerequisites (taxes under &sect;16.025, a registered or recorded deed) are stricter and more formalized than common-law adverse possession. An <strong>encroachment</strong>&mdash;a fence, eave, building, or driveway intruding onto a neighbor&mdash;can mature into title only through these statutory tracks, or into a use-right by prescriptive easement (both hard to prove in Texas). Texas has <strong>no special \"innocent improver\" statute</strong> letting a good-faith encroacher simply buy the strip; title passes only through the statutory tracks, and Texas applies <strong>acquiescence / agreed-boundary</strong> doctrines narrowly. The surveyor''s measured boundary is usually dispositive of where the line is&mdash;and therefore of whether an encroachment exists.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0011-0000-0000-000000000004', 'acc04b11-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Color of title vs. title (§16.021)","content":"<p>\"<strong>Title</strong>\" means a <em>regular</em> chain of transfers from or under the sovereignty of the soil. \"<strong>Color of title</strong>\" means a consecutive chain that is <em>not</em> a regular chain from the sovereign, or a regular chain with a missing or defective link. The distinction drives the 3-year track (&sect;16.024): the stronger your paper basis, the shorter the period the law requires before title ripens&mdash;hence the 3-year period is reserved for possession under title or color of title.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0011-0000-0000-000000000005', 'acc04b11-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Texas adverse possession is wholly statutory: §§16.024–16.028 (3/5/10/25/25-year tracks), in the Civ. Prac. & Rem. Code.","The 5-year track requires paying applicable taxes and a duly registered (non-quitclaim) deed.","The 10-year track needs no instrument but is capped at 160 acres absent enclosure or a recorded deed.","Tacking requires privity; encroachments mature into title only through the strict statutory tracks.","Texas has no innocent-improver statute and applies acquiescence/agreed-boundary doctrines narrowly."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0012-0000-0000-000000000000', 'acc04b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What an Easement Is</h3><p>An <strong>easement</strong> is a non-possessory right to use another''s land for a specified purpose&mdash;access, utilities, drainage. The land benefited is the <em>dominant</em> estate; the land burdened is the <em>servient</em> estate. Easements are created in several ways, and Texas has strong preferences among them. <strong>Express</strong> easements&mdash;created by a written instrument satisfying the Statute of Frauds (Tex. Bus. &amp; Com. Code &sect;26.01)&mdash;are the <strong>most-favored</strong> method, because Texas <em>disfavors</em> the implied and prescriptive routes. In practice, that means most Texas access rights are documented expressly rather than created by operation of law.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0012-0000-0000-000000000001', 'acc04b12-0000-0000-0000-000000000001', 'table', '{"headers":["Type","How created / core test"],"rows":[["Express","Written grant or reservation (Statute of Frauds); most favored in Texas"],["Implied by prior use","Unity of ownership before severance; use open/apparent, continuous, reasonably necessary"],["By necessity","Unity of ownership before severance; strict necessity (true landlock); necessity existed at severance"],["Prescriptive","Open/notorious, continuous, adverse, AND exclusive use for 10 yr — disfavored in Texas"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0012-0000-0000-000000000002', 'acc04b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Necessity vs. Prior Use After Hamrick v. Ward</h3><p>An <strong>easement by necessity</strong> requires all three of: (1) <strong>unity of ownership</strong> of the dominant and servient estates as a single tract <em>before severance</em>; (2) access that is a <strong>present strict necessity, not a mere convenience</strong> (true landlock&mdash;no other legal access); and (3) necessity that <strong>existed at the time of severance</strong>. The easement <strong>terminates when the necessity ends</strong> (e.g., when alternative legal access becomes available). Unity of ownership is enforced rigorously: the grantor must have owned both estates \"as a unit or single tract\" (<em>Koonce v. Brite Estate</em>, 663 S.W.2d 451 (Tex. 1984); reaffirmed in <em>Staley Family P''ship v. Stiles</em>, 483 S.W.3d 545 (Tex. 2016)). In <em>Hamrick v. Ward</em>, 446 S.W.3d 377 (Tex. 2014), the Court held that a party claiming road access to a landlocked, previously unified parcel must proceed under <strong>necessity, not prior use</strong>&mdash;narrowing a doctrine unsettled in Texas for over a century. Prior use still applies to <em>non-access</em> uses (utility lines, drainage) where it remains reasonably necessary.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0012-0000-0000-000000000003', 'acc04b12-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Case: Tran v. Macha — prescriptive easements disfavored","content":"<p>Texas <strong>does not favor prescriptive easements</strong> and scrutinizes every element. Besides being open/notorious, continuous, and adverse for the 10-year period, the use must be <strong>exclusive</strong>&mdash;and in Texas \"exclusive\" means use by the claimant and <em>not</em> by the landowner. <strong>Joint or shared use defeats the claim.</strong> In <em>Tran v. Macha</em>, 213 S.W.3d 913 (Tex. 2006), neighbors shared a driveway under a mutual mistake; the Texas Supreme Court <strong>reversed</strong> the easement, holding that mutual/joint use cannot support an exclusive, hostile claim&mdash;\"joint use of a road, no matter how long, cannot ripen into a prescriptive easement.\" Because most driveway and road-sharing fact patterns involve some owner use, Texas prescriptive claims rarely succeed, and access disputes are funneled toward necessity easements and express grants.</p>","open":false}]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0012-0000-0000-000000000004', 'acc04b12-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs (critical): Under the general common law / Restatement view an easement is non-possessory, so most states do NOT require exclusivity for prescription — shared road use can create one. Texas is the opposite: shared/joint use is normally fatal (Tran v. Macha). Texas also channels landlocked road access into the stricter necessity framework (Hamrick v. Ward)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0012-0000-0000-000000000005', 'acc04b12-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Express easements (written, Statute of Frauds) are the most-favored creation method in Texas.","Easement by necessity: unity of ownership before severance + strict necessity + necessity at severance; ends when necessity ends.","Unity of ownership is enforced rigorously (Koonce; Staley).","Hamrick v. Ward channels landlocked road access into necessity, not prior use.","Texas disfavors prescriptive easements; joint/shared use defeats exclusivity (Tran v. Macha)."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0013-0000-0000-000000000000', 'acc04b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From the Field to the Witness Stand</h3><p>When a boundary dispute reaches court, the surveyor is frequently the central <strong>expert witness</strong>. The <em>location</em> of a survey line is a <strong>question of fact</strong> (<em>TH Investments v. Kirby Inland Marine</em>, 218 S.W.3d 173 (Tex. App.&mdash;Houston [14th Dist.] 2007)), and the factfinder&mdash;judge or jury&mdash;decides it on the evidence. The surveyor''s job is to <strong>explain that evidence</strong>: what monuments were found and set, how the original surveyor''s footsteps were traced, how the dignity-of-calls hierarchy and the intent of the grant resolve the conflicting calls. The surveyor testifies to <em>where the boundary is</em>; the court decides <em>who owns</em> the disputed strip.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0013-0000-0000-000000000001', 'acc04b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Duties of the Expert</h3><p>An expert surveyor owes duties of <strong>competence, objectivity, and candor</strong>. Opinions must rest on adequate evidence&mdash;record research (GLO, deed records, plats), field recovery of monuments, and a defensible retracement methodology&mdash;not on advocacy for the retaining party. The surveyor must disclose the bases of an opinion, acknowledge contrary evidence and reasonable alternative interpretations, and resist pressure to shade the boundary toward the client. Credibility on cross-examination is built in the field months earlier, through <strong>complete field notes, photographs, and a documented chain of reasoning</strong> from evidence to conclusion. The surveyor must also remember the lane boundary: render opinions on boundary <em>location and survey practice</em>, not legal conclusions about title, which are for the court and counsel.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0013-0000-0000-000000000002', 'acc04b13-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Practice point: An expert opinion is only as strong as its evidentiary foundation. Document every found and set monument, the record sources consulted, and the reasoning by which intent, footsteps, and the dignity of calls led to the located line — that record is what survives cross-examination."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0013-0000-0000-000000000003', 'acc04b13-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Limitations period for suits against surveyors","content":"<p>Surveyors can be sued for negligent surveys, and Texas sets a specific limitations period for such suits in <strong>Civ. Prac. &amp; Rem. Code &sect;16.011</strong>. This is one reason expert-quality documentation matters even on routine jobs: a defensible, well-recorded methodology both supports your testimony when you are the retained expert and protects you when your own work is challenged. Treat every boundary survey as potential exhibit evidence.</p>","open":false}]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0013-0000-0000-000000000004', 'acc04b13-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Boundary location is a question of fact; the surveyor supplies the evidence and the court decides.","An expert testifies to where the boundary is — not who owns the disputed land.","Expert opinions must rest on record research, monument recovery, and a defensible retracement method.","Objectivity and candor (acknowledging contrary evidence) build credibility on cross-examination.","Complete field documentation both strengthens testimony and guards against §16.011 surveyor-liability suits."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0014-0000-0000-000000000000', 'acc04b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Who Regulates Texas Surveyors</h3><p>Texas surveyor licensing flows from the <strong>Occupations Code, Chapter 1071</strong>&mdash;the Professional Land Surveying Practices Act&mdash;which defines the credentials and sets qualifications and discipline. The regulator is the <strong>Texas Board of Professional Engineers and Land Surveyors (TBPELS)</strong>, created by HB 1523 (86th Legislature, 2019), which <em>merged</em> the former separate engineering and surveying boards into one. A <strong>Registered Professional Land Surveyor (RPLS)</strong> is licensed by TBPELS; only an RPLS (or, for state land, an <strong>LSLS</strong>) may prepare a metes-and-bounds description, delineate and monument boundaries, and seal and sign the survey.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0014-0000-0000-000000000001', 'acc04b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Standards of Practice — 22 TAC Chapter 138</h3><p>The current Professional and Technical Standards are in <strong>22 TAC Chapter 138, Subchapter E (&sect;&sect;138.81 et seq.)</strong>, \"Compliance and Professionalism for Surveyors.\" Key sections: &sect;138.83 (<strong>Precision and Accuracy</strong>&mdash;traverse and closure tolerances); &sect;138.87 (<strong>Monumentation</strong>&mdash;monuments \"set at sufficient depth to retain a stable and distinctive location\" and traceable to the responsible registrant); and &sect;138.91 (<strong>Survey Drawing / Written Description / Report</strong>&mdash;definite and unambiguous boundaries, stated basis of bearing, and identification of which monuments were found versus placed). A Category 1A land-title survey&mdash;the highest Texas standard&mdash;must certify substantial compliance with the current TSPS <em>Manual of Practice</em> and include a separate closure report.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0014-0000-0000-000000000002', 'acc04b14-0000-0000-0000-000000000001', 'callout', '{"type":"error","text":"Do not cite 22 TAC Chapter 663 (or Ch. 661). Those surveying standards were repealed and merged into Ch. 138 after the 2019 TBPELS consolidation. Citing §663 is outdated for 2026; the standards of practice are now in 22 TAC Ch. 138, Subchapter E."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0014-0000-0000-000000000003', 'acc04b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Core Ethical Obligations</h3><p>Beyond technical accuracy, a surveyor owes ethical duties that the TBPELS rules embody. Retracement work must <strong>honor junior/senior rights and the record chain</strong>&mdash;the surveyor follows the evidence to the legally correct line rather than to the line a client wishes existed. Monuments must be set and documented honestly (found vs. placed). The surveyor must practice only within the scope of the license, avoid the unauthorized practice of law (no title opinions), disclose conflicts, and protect public welfare&mdash;an inaccurate boundary harms not only the client but the neighbors and successors who rely on the record for generations. Competence, integrity, and independence are the through-line of the standards.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0014-0000-0000-000000000004', 'acc04b14-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Licensing flows from Occupations Code Ch. 1071; the regulator is TBPELS (merged 2019).","Standards of practice are in 22 TAC Ch. 138, Subch. E (§§138.81 et seq.) — never cite repealed Ch. 663.","Only an RPLS (or LSLS for state land) may prepare descriptions and seal surveys.","Rules require honoring junior/senior rights, the record chain, and proper monumentation (§138.87).","Ethics: competence, integrity, independence, no unauthorized practice of law, protect public welfare."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0015-0000-0000-000000000000', 'acc04b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>A Coherent Framework</h3><p>This course is really one connected argument. <strong>Texas titles trace to a sovereign</strong> (Spain, Mexico, the Republic, the State) and were never federal public domain, so Texas land is described by <strong>metes-and-bounds tied to a GLO survey and abstract</strong>, not a PLSS grid. When descriptions conflict, you resolve them by <strong>intent</strong> first, then the <strong>footsteps of the original surveyor and found monuments</strong>, and only then the <strong>dignity-of-calls hierarchy</strong>. Special boundaries (water, easements, adverse possession) layer Texas-specific rules on top of that base. The final exam rewards students who can move fluidly across these doctrines in a single fact pattern.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0015-0000-0000-000000000001', 'acc04b15-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Leading Texas cases — quick review","content":"<ul><li><strong>Stafford v. King</strong>, 30 Tex. 257 (1867) — dignity of calls (natural &gt; artificial &gt; course/distance) and the footsteps doctrine; both yield to intent.</li><li><strong>Motl v. Boyd</strong>, 286 S.W. 458 (Tex. 1926), refined by <strong>Brainard v. State</strong>, 12 S.W.3d 6 (Tex. 2000) — the gradient boundary for navigable streams.</li><li><strong>Luttes v. State</strong>, 324 S.W.2d 167 (Tex. 1959) — dual coastal datum (Spanish/Mexican = MHHW; Anglo/Texas = mean high tide).</li><li><strong>Tran v. Macha</strong>, 213 S.W.3d 913 (Tex. 2006) — joint use defeats a prescriptive easement.</li><li><strong>Hamrick v. Ward</strong>, 446 S.W.3d 377 (Tex. 2014) — landlocked road access goes through necessity, not prior use.</li><li><strong>Koonce v. Brite Estate</strong>, 663 S.W.2d 451 (Tex. 1984) — unity of ownership for easement by necessity.</li><li><strong>Madison v. Gordon</strong>, 39 S.W.3d 604 (Tex. 2001) — possession as constructive notice must be visible, open, exclusive, and unequivocal.</li><li><strong>Geodyne v. Newton</strong>, 161 S.W.3d 482 (Tex. 2005) — quitclaim conveys the grantor''s rights ''if any''; classification turns on the granting language.</li></ul>","open":false}]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0015-0000-0000-000000000002', 'acc04b15-0000-0000-0000-000000000001', 'table', '{"headers":["Topic","Texas-specific point to remember"],"rows":[["Recording act","Texas is a pure NOTICE state (§13.001/§13.002): a later BFP without notice wins even if it records second or never"],["Quitclaim/BFP","Grantee generally not a BFP; §13.006 (2021) adds a four-year cleansing window downstream"],["Estates","§5.042 abolished Shelley''s Case and Worthier Title — but not destructibility"],["Water boundary","Gradient boundary on navigable streams; 30-ft navigability rule; dual coastal datum"],["Easements","Prescriptive disfavored (exclusivity / Tran v. Macha); necessity channeled by Hamrick"],["Adverse possession","Statutory §§16.024–16.028; 5-yr track needs taxes; 10-yr capped at 160 acres"],["Standards","22 TAC Ch. 138 (not repealed Ch. 663); TBPELS since 2019"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0015-0000-0000-000000000003', 'acc04b15-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Final-exam strategy: For every scenario, first ask ''what is the controlling intent?'' and ''whose footsteps/monuments govern?'' before reaching for a mechanical rule. Then flag any Texas divergence (notice state, gradient boundary, statutory adverse possession, disfavored prescription, Ch. 138 standards)."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0015-0000-0000-000000000004', 'acc04b15-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Resolve boundary conflicts by intent → footsteps/monuments → dignity of calls.","Stafford v. King (calls + footsteps); Motl/Brainard (gradient boundary); Luttes (dual coastal datum).","Tran v. Macha and Hamrick v. Ward define Texas''s restrictive treatment of prescriptive and prior-use easements.","Texas is a pure notice recording state; the quitclaim grantee is generally not a BFP (with the §13.006 window).","Adverse possession is statutory (§§16.024–16.028); current standards are 22 TAC Ch. 138."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0016-0000-0000-000000000000', 'acc04b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Final Exam Scope</h3><p>The Week 16 final is a <strong>comprehensive, application-focused</strong> assessment over the entire course: sources of law and the court system; estates and deeds; legal descriptions (metes-and-bounds, PLSS, lot-and-block); the Texas land system and Spanish/Mexican grants; boundary evidence and the priority of calls; original versus retracement surveys; riparian and littoral boundaries; adverse possession; easements and rights-of-way; the surveyor as expert witness; and professional ethics and Texas standards. Expect multi-issue scenarios that ask you to integrate doctrine rather than recite isolated rules.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0016-0000-0000-000000000001', 'acc04b16-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Reminder: This course supplies the legal foundation for the Surveyor-in-Training (SIT) and RPLS examinations. The final exam mirrors that style — apply current Texas authority, reason from intent and footsteps, and flag the Texas-specific divergences that distinguish this state from general common-law practice."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3210-0016-0000-0000-000000000002', 'acc04b16-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The final is comprehensive across all 14 instructional weeks and application-focused.","Reason from intent and footsteps first; mechanical rules are tie-breakers.","Cite current authority (§§16.024–16.028, 22 TAC Ch. 138, §13.006), not repealed rules.","This course feeds the legal-principles portion of the SIT and RPLS exams."]}'::jsonb, 2);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000001', 'Hierarchy of Texas law', 'From highest to lowest authority: the Texas Constitution (1876), statutes (topical codes), administrative rules (Texas Administrative Code), and case law (common law / stare decisis).', 'Four layers; the Constitution is on top.', 'acc00004-0000-0000-0000-000000000004', 'acc04b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000002', 'Trespass to try title', 'The statutory civil action in Texas used to determine title to and possession of real property; it begins in a District Court (general jurisdiction).', 'The Texas vehicle for boundary/title disputes.', 'acc00004-0000-0000-0000-000000000004', 'acc04b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000003', 'Split-apex court system', 'Texas''s design of two co-equal highest courts: the Supreme Court of Texas (final for civil cases, including boundary/title) and the Court of Criminal Appeals (final for criminal cases). Shared only with Oklahoma.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000004', 'Fee simple determinable', 'A defeasible fee created with durational language (''so long as,'' ''until'') that automatically reverts to the grantor upon the stated event, leaving the grantor a possibility of reverter.', 'Automatic reversion; durational words.', 'acc00004-0000-0000-0000-000000000004', 'acc04b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000005', 'Possibility of reverter vs. right of re-entry', 'A possibility of reverter follows a fee simple determinable and revests title automatically; a right of re-entry (power of termination) follows a fee simple subject to condition subsequent and must be affirmatively exercised by the grantor.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000006', 'Tex. Prop. Code §5.042', 'Statute (eff. 1984) abolishing the Rule in Shelley''s Case, the Doctrine of Worthier Title, the rule against a remainder to the grantor''s heirs, and a homestead-lien rule, giving effect to such limitations per the grantor''s intent.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000007', 'Special warranty deed', 'A deed in which the grantor warrants title only against defects arising ''by, through, or under'' the grantor — not against earlier links in the chain of title.', 'Narrower than general; only the grantor''s own acts.', 'acc00004-0000-0000-0000-000000000004', 'acc04b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000008', 'Quitclaim deed (Texas)', 'A deed conveying only whatever interest the grantor has, if any, with no warranty. It is not a muniment of title, and its grantee is generally not a bona fide purchaser (subject to the §13.006 four-year cleansing window for recordings after Sept. 1, 2021).', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000009', 'Four-corners rule', 'The Texas rule that a deed is construed according to the intent expressed within the four corners of the instrument, harmonizing all of its parts; a specific description controls over a general one when they conflict.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000010', 'Point of Beginning (POB)', 'The defined origin of a metes-and-bounds perimeter run, conventionally tied to a corner of the original GLO survey/abstract so the tract can be relocated independently of the surveyor''s work.', 'Where the perimeter starts and closes.', 'acc00004-0000-0000-0000-000000000004', 'acc04b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000011', 'Abstract number', 'The identifier assigned to an original Texas land-grant survey by the General Land Office; the spine of Texas land identification, recited in nearly every Texas description caption.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000012', 'Basis of bearing', 'The stated reference to which the courses of a survey are oriented — under 22 TAC §138.91(c), an identifiable monumented line or an established geodetic system such as the Texas State Plane Coordinate System (NAD83).', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000013', 'Public Land Survey System (PLSS)', 'The federal rectangular survey system dividing public-domain land into townships (~6 mi square), located by township and range, each containing 36 sections of about 640 acres. Texas never adopted it.', 'Township, range, section — federal grid.', 'acc00004-0000-0000-0000-000000000004', 'acc04b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000014', 'Lot-and-block description', 'A description that identifies a parcel by its lot and block within a named subdivision as shown on a plat recorded with the county clerk, citing the plat''s recording reference.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000015', 'Section (PLSS)', 'A PLSS subdivision of a township, nominally one square mile (640 acres); 36 sections make up a township, numbered 1–36 in a back-and-forth pattern.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000016', 'Sovereigns of the soil (Texas)', 'The four sources of original Texas land title: Spain, Mexico, the Republic of Texas, and the State of Texas. Every Texas chain of title runs back to one of them.', 'Four, in chronological order.', 'acc00004-0000-0000-0000-000000000004', 'acc04b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000017', 'Vara (Texas)', 'The historic Texas linear unit, fixed by Texas law at exactly 33⅓ inches (2.7778 ft); 36 varas equal exactly 100 feet. Common in original GLO field notes (abbreviated ''vrs'').', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000018', 'League and labor', 'Texas area units: a labor is 1,000,000 sq varas (~177 acres, farmland) and a league (sitio) is 25,000,000 sq varas (~4,428 acres, grazing land, = 25 labors). The standard family colonization grant was one league + one labor (~4,605 acres).', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000019', 'Dignity of calls', 'The hierarchy ranking conflicting calls by reliability: natural monuments > artificial monuments > adjoinder > course (bearing) > distance > quantity/area. It is a rule of construction that yields to intent and to the original surveyor''s footsteps.', 'Most permanent call wins.', 'acc00004-0000-0000-0000-000000000004', 'acc04b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000020', 'Footsteps doctrine', 'The principle (from Stafford v. King, 30 Tex. 257 (1867)) that the lines and corners actually run and marked by the original surveyor control retracement, even over inconsistent field-note calls, where they can be ascertained.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000021', 'Senior/junior rights', 'In sequential conveyances, the earlier (senior) deed takes the full measure of its description and the later (junior) deed takes only the remainder; the grantor cannot convey what was already conveyed, so the junior absorbs excess or deficiency.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000022', 'Midterm high-yield (Texas traps)', '§5.042 abolitions (not destructibility), §5.023 narrowed implied covenants, §13.006 four-year quitclaim cleansing window, 22 TAC Ch. 138 (not repealed Ch. 663), no PLSS grid in Texas, dignity of calls subordinate to intent and footsteps.', 'The points where Texas diverges from general common law.', 'acc00004-0000-0000-0000-000000000004', 'acc04b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000023', 'Order of boundary-conflict analysis', 'Resolve conflicting calls by (1) the parties'' intent within the four corners, (2) the footsteps of the original surveyor and found monuments, and only then (3) the dignity-of-calls hierarchy.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000024', 'Retracement (resurvey)', 'A survey that re-establishes the lines and corners of an existing original survey; it does not create or relocate boundaries. The footsteps of the original surveyor control.', 'Recover, don''t create.', 'acc00004-0000-0000-0000-000000000004', 'acc04b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000025', 'Obliterated vs. lost corner', 'An obliterated corner has no surviving physical evidence but its position is recoverable from collateral evidence (occupation, testimony, ties); a lost corner cannot be recovered by acceptable evidence and is re-established by proportionate measurement.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000026', 'Licensed State Land Surveyor (LSLS)', 'A Texas credential, higher than RPLS and issued through the GLO, required to survey land in which the State or Permanent School Fund has an interest, including locating or relocating original land-grant boundaries and corners.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000027', 'Gradient boundary', 'The Texas method for locating the landward limit of a navigable stream''s bed: a graded line along the bank midway between the water level that just reaches the cut bank and the level that just fails to overtop it (Motl v. Boyd; Brainard v. State).', 'Mid-height of the qualified bank.', 'acc00004-0000-0000-0000-000000000004', 'acc04b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000028', '30-foot navigability rule', 'Tex. Nat. Res. Code §21.001(3): a ''navigable stream'' is one that retains an average bed width of 30 feet from its mouth up. Such streams are public, with a State-owned bed.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000029', 'Luttes dual coastal datum', 'From Luttes v. State (1959): the seaward boundary of upland is mean higher high water for Spanish/Mexican grants but mean high tide (mean high water) for Anglo-American (Republic/State) grants.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000030', 'Texas adverse-possession tracks', 'Five statutory limitation periods in Civ. Prac. & Rem. Code Ch. 16: §16.024 (3 yr, title/color of title), §16.025 (5 yr, taxes + registered deed), §16.026 (10 yr, 160-acre cap), §16.027 (25 yr, despite disability), §16.028 (25 yr, recorded but void instrument).', '3 / 5 / 10 / 25 / 25.', 'acc00004-0000-0000-0000-000000000004', 'acc04b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000031', 'Five-year track tax requirement', 'Under §16.025 the claimant must cultivate/use/enjoy the land, pay applicable property taxes each year, and claim under a duly registered (non-quitclaim) deed. A single missed tax year defeats the claim.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000032', 'Color of title (§16.021)', 'A consecutive chain of transfers that is not a regular chain from the sovereign, or a regular chain with a missing or defective link; it supports the shortest (3-year) adverse-possession track under §16.024.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000033', 'Easement by necessity (Texas elements)', 'Requires (1) unity of ownership of dominant and servient estates as one tract before severance, (2) strict necessity (true landlock, not convenience), and (3) necessity existing at the time of severance. It terminates when the necessity ends.', 'Unity + strict necessity + at severance.', 'acc00004-0000-0000-0000-000000000004', 'acc04b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000034', 'Prescriptive easement exclusivity (Texas)', 'In Texas a prescriptive easement requires exclusive use — use by the claimant and not the landowner. Joint or shared use, however long, cannot ripen into a prescriptive easement (Tran v. Macha, 2006).', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000035', 'Hamrick v. Ward', 'Texas Supreme Court case (2014) holding that a claim of roadway access to a landlocked, previously unified parcel must proceed under easement by necessity, not implied easement by prior use.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000036', 'Boundary location as a question of fact', 'Under Texas law (e.g., TH Investments v. Kirby Inland Marine) the location of a survey line is a fact question decided by the factfinder; the surveyor''s role is to present the evidence and reasoning, not to decide ownership.', 'Surveyor presents; court decides.', 'acc00004-0000-0000-0000-000000000004', 'acc04b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000037', 'Expert surveyor''s duty of candor', 'The obligation to base opinions on adequate evidence, disclose the bases of those opinions, acknowledge contrary evidence and reasonable alternatives, and remain objective rather than advocate for the retaining party.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000038', 'TBPELS', 'The Texas Board of Professional Engineers and Land Surveyors, created by HB 1523 (2019) by merging the former engineering and surveying boards; it licenses surveyors and adopts the standards of practice in 22 TAC Ch. 138.', 'The merged 2019 board.', 'acc00004-0000-0000-0000-000000000004', 'acc04b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000039', '22 TAC Chapter 138', 'The current Texas administrative rules (''Compliance and Professionalism for Surveyors''); Subchapter E (§§138.81 et seq.) holds the Professional and Technical Standards (precision §138.83, monumentation §138.87, descriptions §138.91). It replaced the repealed Ch. 663.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000040', 'RPLS vs. LSLS', 'A Registered Professional Land Surveyor (RPLS) is the TBPELS license to practice land surveying; a Licensed State Land Surveyor (LSLS) is the higher GLO credential required to survey land in which the State or Permanent School Fund has an interest.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000041', 'Texas as a notice state', 'Under Tex. Prop. Code §13.001/§13.002, Texas is a pure notice recording jurisdiction: a subsequent purchaser for value without notice of a prior unrecorded conveyance prevails — even if that purchaser records second or never records at all.', 'Recording order is irrelevant to the BFP''s win.', 'acc00004-0000-0000-0000-000000000004', 'acc04b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000042', 'Madison v. Gordon possession test', 'Possession imparts constructive notice that defeats a bona fide purchaser only if it is ''visible, open, exclusive, and unequivocal'' — a stricter four-adjective Texas formulation than the looser ''open and notorious'' standard.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000043', 'Comprehensive final scope', 'Covers all course topics: legal sources/courts, estates, deeds, descriptions, the Texas land system, priority of calls, original vs. retracement surveys, water boundaries, adverse possession, easements, expert testimony, and ethics/standards.', 'Everything from Weeks 1–15.', 'acc00004-0000-0000-0000-000000000004', 'acc04b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3240-0000-0000-0000-000000000044', 'Cite-current rule of thumb', 'On the final and in practice, cite current Texas authority — adverse possession §§16.024–16.028, standards 22 TAC Ch. 138, quitclaim §13.006 — and avoid superseded rules such as 22 TAC Ch. 663.', NULL, 'acc00004-0000-0000-0000-000000000004', 'acc04b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-32']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000001', 'A boundary dispute over a residential lot line is filed in Texas. Through which court path will the case ultimately be resolved on a question of law?', 'multiple_choice', '["District Court → Court of Appeals → Supreme Court of Texas","Justice Court → County Court → Court of Criminal Appeals","Municipal Court → Court of Appeals → Court of Criminal Appeals","County Court → Supreme Court of Texas → U.S. Supreme Court"]'::jsonb, 'District Court → Court of Appeals → Supreme Court of Texas', 'Boundary/title disputes are civil matters that begin in District Court, may be appealed to a Court of Appeals, and end at the Supreme Court of Texas. The Court of Criminal Appeals handles only criminal cases and never touches boundary precedent.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b01-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000002', 'A student looks for the Texas adverse-possession statutes in the Property Code and cannot find them. Why?', 'multiple_choice', '["Adverse possession is codified in the Civil Practice & Remedies Code, Chapter 16","Adverse possession is purely common law and has no statute in Texas","Adverse possession is in the Natural Resources Code with the GLO provisions","Adverse possession is in the Occupations Code with surveyor licensing"]'::jsonb, 'Adverse possession is codified in the Civil Practice & Remedies Code, Chapter 16', 'A classic Texas trap: adverse possession lives in Civ. Prac. & Rem. Code Ch. 16 (§§16.021–16.028), not the Property Code. It is wholly statutory, not common law.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b01-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000003', 'A deed conveys land ''to the City so long as it is used for a public park.'' What estate and future interest does this create?', 'multiple_choice', '["Fee simple determinable, leaving the grantor a possibility of reverter","Fee simple subject to condition subsequent, leaving a right of re-entry","Life estate, leaving a reversion","Fee simple absolute, leaving no future interest"]'::jsonb, 'Fee simple determinable, leaving the grantor a possibility of reverter', 'The durational phrase ''so long as'' creates a fee simple determinable that automatically reverts on the stated event, leaving the grantor a possibility of reverter. Conditional words like ''but if'' would instead create a condition subsequent with a right of re-entry.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b02-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000004', 'Which common-law rule did Tex. Prop. Code §5.042 NOT abolish?', 'multiple_choice', '["The destructibility of contingent remainders","The Rule in Shelley''s Case","The Doctrine of Worthier Title","The rule forbidding a remainder to the grantor''s heirs"]'::jsonb, 'The destructibility of contingent remainders', 'Section 5.042 abolished Shelley''s Case, Worthier Title, the remainder-to-grantor''s-heirs rule, and a homestead-lien rule. It did NOT abolish destructibility of contingent remainders; Texas rejects that doctrine by case law instead.', 'hard', 'acc00004-0000-0000-0000-000000000004', 'acc04b02-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000005', 'In Texas a conveyance is presumed to pass the entire fee simple unless a lesser estate is expressly limited.', 'true_false', '["True","False"]'::jsonb, 'True', 'Tex. Prop. Code §5.001 provides that a conveyance passes the grantor''s whole estate unless the estate is limited by express words or a lesser estate is conveyed.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b02-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000006', 'A grantor signs a deed warranting title only against defects ''by, through, or under'' himself. What deed is this, and what does the grantee receive?', 'multiple_choice', '["A special warranty deed; protection only against the grantor''s own acts, not earlier links in the chain","A general warranty deed; protection against all defects back through the entire chain","A quitclaim deed; no warranty of any kind","A statutory form deed; an implied covenant of seisin that the grantor owns the land"]'::jsonb, 'A special warranty deed; protection only against the grantor''s own acts, not earlier links in the chain', '''By, through, or under the grantor'' is the hallmark of a special warranty deed: the grantor defends only against defects arising during his own ownership, not against earlier links. A general warranty defends the whole chain.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b03-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000007', 'Under Tex. Prop. Code §5.023, the words ''grant'' or ''convey'' imply which covenants?', 'multiple_choice', '["Only that the grantor has not previously conveyed the estate and that it is free from encumbrances","A full covenant of seisin that the grantor actually owns the estate","A warranty against all defects in the entire chain of title","No covenants at all unless the deed says ''warrant and forever defend''"]'::jsonb, 'Only that the grantor has not previously conveyed the estate and that it is free from encumbrances', 'Section 5.023 narrows the implied covenants to (1) no prior conveyance and (2) no encumbrances. Unlike the common law, it does not imply a covenant of seisin; broad protection requires the express ''warrant and forever defend'' language of §5.022.', 'hard', 'acc00004-0000-0000-0000-000000000004', 'acc04b03-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000008', 'A buyer pays value for land under a quitclaim deed recorded in 2023 and has no actual notice of a prior unrecorded claim. Two years later the prior claimant sues. What is the likely result under current Texas law?', 'multiple_choice', '["The buyer is generally not a bona fide purchaser yet, because §13.006''s cleansing window does not run until the fourth anniversary of recording","The buyer automatically wins as a bona fide purchaser because the quitclaim was recorded","The buyer wins because Texas treats a quitclaim grantee exactly like a warranty-deed grantee","The quitclaim is void and conveys nothing at all"]'::jsonb, 'The buyer is generally not a bona fide purchaser yet, because §13.006''s cleansing window does not run until the fourth anniversary of recording', 'A Texas quitclaim grantee is generally not a BFP. Section 13.006 (2021) provides a cleansing window only after the FOURTH anniversary of recording; at two years the classic rule still applies, so the buyer takes subject to the prior claim.', 'hard', 'acc00004-0000-0000-0000-000000000004', 'acc04b03-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000009', 'In a Texas metes-and-bounds description, which element is treated as the LEAST reliable when calls conflict?', 'multiple_choice', '["Stated area/quantity (acreage)","A called natural monument such as a creek","A called artificial monument such as a set iron rod","The basis of bearing"]'::jsonb, 'Stated area/quantity (acreage)', 'Stated area is the weakest, least-reliable element — a check, not a control. Monuments (natural, then artificial) control over course and distance, and area yields to all of them.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b04-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000010', 'Why does a Texas description caption almost always recite an original survey name and abstract number?', 'multiple_choice', '["Because Texas land is organized by original GLO land-grant surveys, not the federal PLSS grid","Because the abstract number identifies the PLSS section and township","Because federal law requires every deed to reference a principal meridian","Because the abstract number sets the basis of bearing for the survey"]'::jsonb, 'Because Texas land is organized by original GLO land-grant surveys, not the federal PLSS grid', 'Texas land was never federal public domain and has no PLSS grid; it is identified by original survey + abstract number administered by the GLO. The abstract is the spine of Texas land identification.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b04-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000011', 'A surveyor cites ''22 TAC Chapter 663'' as the source of the Texas standards of practice. Is this correct in 2026?', 'true_false', '["True","False"]'::jsonb, 'False', 'Chapter 663 was repealed and merged into 22 TAC Chapter 138 (Subchapter E) after the 2019 board consolidation into TBPELS. Citing §663 is outdated for 2026.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b04-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000012', 'Which statement about the Public Land Survey System (PLSS) and Texas is correct?', 'multiple_choice', '["Texas never adopted the PLSS because it retained its public lands at annexation and uses original survey + abstract descriptions","Texas uses the PLSS township-range grid for all rural land","Texas adopted a modified PLSS administered by the GLO","The PLSS and the Texas abstract system are mathematically interchangeable"]'::jsonb, 'Texas never adopted the PLSS because it retained its public lands at annexation and uses original survey + abstract descriptions', 'Texas entered the Union retaining its public lands, so its land was never surveyed under the federal PLSS. There is no township-range grid in Texas; the two systems are unrelated.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b05-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000013', 'Lots in a recorded subdivision plat are created simultaneously. When a resurvey finds excess between the controlling block monuments, how is it handled?', 'multiple_choice', '["It is apportioned proportionately among the lots; no lot is senior","The first lot sold takes all of the excess as the senior parcel","The last lot in the block absorbs the entire excess","The excess is returned to the original developer as reserved land"]'::jsonb, 'It is apportioned proportionately among the lots; no lot is senior', 'Simultaneously created plat lots have no senior; excess or deficiency between controlling monuments is apportioned in proportion to record lengths. Senior/junior rights apply only to sequential conveyances.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b05-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000014', 'A South Texas chain of title bottoms out in an 1830 Mexican league-and-labor grant. Which statement is correct?', 'multiple_choice', '["A perfected Mexican title remains valid and the land cannot be re-patented by the State","The Mexican grant was extinguished at annexation and must be re-patented","The grant is governed by the federal PLSS as adopted in 1845","The land reverted to the United States as federal public domain in 1845"]'::jsonb, 'A perfected Mexican title remains valid and the land cannot be re-patented by the State', 'Perfected Spanish/Mexican titles remain valid (recognized by the Treaty of Guadalupe Hidalgo and Texas constitutions). Because sovereignty was already severed, the land cannot be re-patented.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b06-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000015', 'Texas land was part of the federal public domain and was surveyed by the federal General Land Office under the PLSS.', 'true_false', '["True","False"]'::jsonb, 'False', 'Texas retained its public lands at annexation in 1845; its land was never federal public domain. The Texas General Land Office (state, not federal) administers the grant records, and there is no PLSS grid in Texas.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b06-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000016', 'An original field note calls for a course of ''N 45° E, 300 ft to a marked oak,'' but the marked oak is found 320 ft away on a bearing of N 47° E. The tree is unquestionably the original monument. Which call controls?', 'multiple_choice', '["The marked oak (a found artificial monument), which controls over the course and distance","The course and distance, because measurements are more precise than a tree","The stated area of the tract, which is the highest-dignity call","Neither; the conflict voids the description"]'::jsonb, 'The marked oak (a found artificial monument), which controls over the course and distance', 'Under the dignity of calls (and Stafford v. King), a found, identifiable monument controls over conflicting course and distance. The footsteps of the original surveyor — here, the marked oak — locate the line.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b07-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000017', 'Which case is the foundational Texas authority for both the dignity-of-calls hierarchy and the footsteps doctrine?', 'multiple_choice', '["Stafford v. King, 30 Tex. 257 (1867)","Motl v. Boyd, 286 S.W. 458 (Tex. 1926)","Tran v. Macha, 213 S.W.3d 913 (Tex. 2006)","Luttes v. State, 324 S.W.2d 167 (Tex. 1959)"]'::jsonb, 'Stafford v. King, 30 Tex. 257 (1867)', 'Stafford v. King is the seminal Texas case stating the dignity of calls (natural > artificial > course/distance) and the footsteps doctrine. The other cases address water boundaries and easements.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b07-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000018', 'A surveyor cannot find the physical evidence of an original corner but can recover its position from old fence lines, a witness''s testimony, and ties to two adjacent original monuments. How should the corner be classified and re-established?', 'multiple_choice', '["Obliterated — re-established from the collateral evidence, not by proportioning","Lost — re-established solely by proportionate measurement","Lost — abandoned and ignored in the retracement","Original — reset wherever the new measurements best close"]'::jsonb, 'Obliterated — re-established from the collateral evidence, not by proportioning', 'An obliterated corner has no surviving physical monument but its position is recoverable from collateral evidence, so it must be re-established from that evidence. Proportioning is reserved for genuinely lost corners after the search for evidence is exhausted.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b09-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000019', 'A retracement (resurvey) may correct and relocate an original boundary to make its measurements close more accurately.', 'true_false', '["True","False"]'::jsonb, 'False', 'A retracement re-establishes existing boundaries; it never creates or relocates them. The footsteps of the original surveyor control even over inconsistent field-note calls.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b09-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000020', 'A creek''s bed averages 35 feet in width from its mouth up, though it is dry several months a year. Under Texas law, who owns the bed?', 'multiple_choice', '["The State of Texas, because the stream is navigable under the 30-foot rule (§21.001(3))","The abutting landowners to the center thread, because the creek is often dry","The federal government under the navigable-waters doctrine","Whoever recorded a deed to the bed first"]'::jsonb, 'The State of Texas, because the stream is navigable under the 30-foot rule (§21.001(3))', 'A stream whose bed averages 30 feet or more in width from the mouth up is navigable under Tex. Nat. Res. Code §21.001(3); the State owns the bed. The 30 feet is measured across the entire bed, so seasonal dryness is irrelevant.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b10-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000021', 'A coastal tract derives from an 1829 Mexican grant. Which datum fixes its seaward boundary under Luttes v. State?', 'multiple_choice', '["Mean higher high water (MHHW)","Mean high tide / mean high water (MHW)","Mean lower low water (MLLW)","The ordinary high-water mark used in PLSS states"]'::jsonb, 'Mean higher high water (MHHW)', 'Under Luttes v. State, Spanish/Mexican grants are bounded by mean higher high water, which lies landward; Anglo-American (Republic/State) grants use mean high tide. The surveyor must trace the chain of title to the sovereign before choosing the datum.', 'hard', 'acc00004-0000-0000-0000-000000000004', 'acc04b10-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000022', 'Texas locates the boundary of a navigable stream at the ordinary high-water mark, the same observable vegetation line used in most other states.', 'true_false', '["True","False"]'::jsonb, 'False', 'Texas uses the gradient boundary (Motl v. Boyd; Brainard) — a computed line at the mid-height of the qualified cut bank — not the ordinary high-water mark used elsewhere.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b10-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000023', 'A claimant has cultivated and enjoyed a tract under a duly registered (non-quitclaim) deed and has paid the property taxes every year except one, in which he forgot. Under the Texas 5-year track, what is the effect?', 'multiple_choice', '["The claim under §16.025 fails because tax payment each year is a hard requirement and one missed year is fatal","The claim still ripens at five years because near-complete tax payment is sufficient","The claim converts automatically to the 3-year track under §16.024","The claim is unaffected because taxes are not required for adverse possession"]'::jsonb, 'The claim under §16.025 fails because tax payment each year is a hard requirement and one missed year is fatal', 'The §16.025 five-year track requires paying applicable property taxes each year; a single missed year defeats the claim. This tax requirement is distinctive to Texas and a frequent claim-killer.', 'hard', 'acc00004-0000-0000-0000-000000000004', 'acc04b11-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000024', 'Under the Texas 10-year adverse-possession track (§16.026), without an enclosure or a recorded deed fixing the boundaries, the claim is capped at how much land?', 'multiple_choice', '["160 acres","640 acres","40 acres","There is no cap"]'::jsonb, '160 acres', 'The §16.026 ten-year track is capped at 160 acres unless a larger area is enclosed or possession is under a recorded deed/memorandum fixing the boundaries. This acreage cap has no general common-law analog.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b11-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000025', 'Two neighbors share a gravel driveway for 20 years under a mutual mistake about the boundary; both use it regularly. One now claims a prescriptive easement. What result under Texas law?', 'multiple_choice', '["No prescriptive easement, because joint/shared use defeats the exclusivity requirement (Tran v. Macha)","A prescriptive easement, because 20 years exceeds the 10-year period","A prescriptive easement, because exclusivity is not required for non-possessory rights","An easement by necessity, because the driveway is the only access"]'::jsonb, 'No prescriptive easement, because joint/shared use defeats the exclusivity requirement (Tran v. Macha)', 'Texas requires exclusive use for prescription — use by the claimant and not the owner. Under Tran v. Macha, joint use ''no matter how long'' cannot ripen into a prescriptive easement, regardless of duration.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b12-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000026', 'A previously unified tract is now landlocked and the owner seeks roadway access across the grantor''s retained land. Under Hamrick v. Ward, which doctrine must the owner use?', 'multiple_choice', '["Easement by necessity (not implied easement by prior use)","Implied easement by prior use, which is easier to prove","Prescriptive easement after ten years of use","Express easement only; no implied route is available"]'::jsonb, 'Easement by necessity (not implied easement by prior use)', 'Hamrick v. Ward holds that a claim of roadway access to a landlocked, previously unified parcel must proceed under easement by necessity, not prior use. Prior use still applies to non-access uses like utilities.', 'hard', 'acc00004-0000-0000-0000-000000000004', 'acc04b12-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000027', 'Testifying as a surveying expert in a boundary case, what is the proper scope of the surveyor''s opinion?', 'multiple_choice', '["Where the boundary is located, based on the evidence — not who legally owns the disputed strip","Both where the boundary is and who holds legal title to the land","Whether the deed is legally valid and enforceable","How the court should rule on the parties'' competing claims"]'::jsonb, 'Where the boundary is located, based on the evidence — not who legally owns the disputed strip', 'Boundary location is a question of fact the surveyor''s evidence informs, but the surveyor testifies to where the line is, not who owns the land or how the case should be decided — those are for the court and counsel.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b13-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000028', 'Which authority currently governs the Texas surveyor''s standards of practice and the requirement to document which monuments were found versus placed?', 'multiple_choice', '["22 TAC Chapter 138, Subchapter E (TBPELS)","22 TAC Chapter 663 (the former surveying board)","The federal BLM Manual of Surveying Instructions","The Texas Property Code, Chapter 5"]'::jsonb, '22 TAC Chapter 138, Subchapter E (TBPELS)', 'Current standards are in 22 TAC Ch. 138, Subch. E, adopted by TBPELS; §138.91 requires identifying found versus placed monuments. Chapter 663 was repealed; the BLM Manual governs the federal PLSS, not Texas standards.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b14-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000029', 'Only a Registered Professional Land Surveyor (or an LSLS for state land) may prepare a metes-and-bounds description and seal the survey in Texas.', 'true_false', '["True","False"]'::jsonb, 'True', 'Under Occupations Code Ch. 1071, only an RPLS (or LSLS for land in which the State/PSF has an interest) may prepare descriptions, delineate/monument boundaries, and seal and sign the survey.', 'easy', 'acc00004-0000-0000-0000-000000000004', 'acc04b14-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000030', 'Texas is which type of recording jurisdiction with respect to a subsequent purchaser for value without notice?', 'multiple_choice', '["A pure notice state — the later BFP without notice prevails even if it records second or never","A race state — the first to record always wins, even with notice","A race-notice state — the BFP wins only if it also records first","A first-in-time state with no recording statute"]'::jsonb, 'A pure notice state — the later BFP without notice prevails even if it records second or never', 'Under §13.001/§13.002 Texas is a pure notice state: a subsequent purchaser for value without notice of a prior unrecorded conveyance prevails, with no recording-priority requirement for the BFP.', 'hard', 'acc00004-0000-0000-0000-000000000004', 'acc04b15-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000031', 'Under Madison v. Gordon, possession imparts constructive notice that defeats a bona fide purchaser only if the possession is:', 'multiple_choice', '["Visible, open, exclusive, and unequivocal","Merely open and notorious, as in most states","Recorded with the county clerk","Continuous for at least ten years"]'::jsonb, 'Visible, open, exclusive, and unequivocal', 'Madison v. Gordon requires possession to be ''visible, open, exclusive, and unequivocal'' to charge a purchaser with constructive notice — a stricter, four-adjective Texas test than the looser ''open and notorious'' standard.', 'medium', 'acc00004-0000-0000-0000-000000000004', 'acc04b15-0000-0000-0000-000000000001', ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3230-0000-0000-0000-000000000032', 'Across the course, when a single description contains conflicting calls, in what order should a Texas surveyor resolve the conflict?', 'multiple_choice', '["Intent of the parties → footsteps/found monuments → dignity-of-calls hierarchy","Dignity-of-calls hierarchy → stated area → intent","Distance → course → monuments → intent","Recording date → tax payment → dignity of calls"]'::jsonb, 'Intent of the parties → footsteps/found monuments → dignity-of-calls hierarchy', 'Intent within the four corners is paramount; next come the footsteps of the original surveyor and found monuments; the mechanical dignity-of-calls hierarchy is only the final tie-breaker.', 'medium', 'acc00004-0000-0000-0000-000000000004', NULL, ARRAY['buildout','module-32']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3260-0000-0000-0000-000000000001', 'A claimant has held peaceable and adverse possession of a Texas tract, cultivating and using it, paying all applicable property taxes each year, and claiming under a duly registered (non-quitclaim) deed, since {{startYear}}. Under the Texas 5-year limitation track (Civ. Prac. & Rem. Code §16.025), in what calendar year does the limitation period first ripen into perfected title?', 'numeric_input', '[]'::jsonb, '0', 'Because the claimant holds under a duly registered deed, uses the land, and pays taxes each year, the 5-year track (§16.025) applies. Title ripens 5 years after possession began: {{startYear}} + 5 = {{_answer}}.', 'easy', 'acc00004-0000-0000-0000-000000000004', NULL, ARRAY['buildout','module-32','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3250-0000-0000-0000-000000000001', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3260-0000-0000-0000-000000000002', 'A block of {{n}} lots was platted simultaneously, each with a record frontage of {{rec:f2}} ft (record total {{recTotal:f2}} ft). A resurvey between the two controlling original block-corner monuments measures an actual total of {{meas:f2}} ft. Using single proportionate measurement, what corrected frontage (ft) should each equal lot receive?', 'numeric_input', '[]'::jsonb, '0', 'Plat lots are created simultaneously, so the measured surplus/deficiency is distributed proportionately to record frontage. With equal record lots, each corrected frontage is the measured total divided by the number of lots: {{meas:f2}} ÷ {{n}} = {{_answer}} ft.', 'medium', 'acc00004-0000-0000-0000-000000000004', NULL, ARRAY['buildout','module-32','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3250-0000-0000-0000-000000000002', 0.05);
